// Build systemPrompt + userPrompt for the Basic LLM Chain.
// Encodes 3-axis intensity metrics (작성 / 이행 / 체크) so the LLM can
// reflect actual user execution patterns instead of just numeric averages.
const body = $input.first().json.body || {};
if (!body.user_id || !body.data) {
  return [{ json: { valid: false, reason: 'missing_fields', body } }];
}
const d = body.data || {};
const locale = body.user_locale || 'ko';
const period = (body.period || 'weekly');

const pct = (n) => Math.round((Number(n) || 0) * 100);
const todoRate = d.todos_total ? Math.round(((d.todos_completed || 0) / d.todos_total) * 100) : 0;
const onTimeRate = d.todos_completed ? Math.round(((d.todos_completed_on_due_day || 0) / d.todos_completed) * 100) : 0;
const execRate = d.planned_minutes ? Math.round(((d.actual_focus_minutes || 0) / d.planned_minutes) * 100) : 0;
const grades = d.sessions_by_grade || {};
const gradeStr = ['S','A','B','C','D'].map(g => `${g}:${grades[g]||0}`).join(' ');
const categoryStr = Object.entries(d.category_distribution || {}).map(([k,v]) => `${k}:${v}`).join(' ') || '없음';

const systemPrompt = [
  'You are a wellness coach producing a structured JSON report in Korean.',
  'Output ONLY a single JSON object — NO markdown, NO reasoning prose.',
  'Schema: { summary (string ≤160 chars), insights (3-5 short Korean strings), suggestions (2-3 short Korean strings), encouragement (1 positive Korean sentence) }.',
  'Use the three intensity axes (작성/이행/체크) when forming insights — point out imbalances if any.',
  `Locale: ${locale}. Period: ${period}.`
].join('\n');

const userPrompt = [
  '[작성 강도 — Authoring]',
  `- 신규 일정 ${d.schedules_created||0}개, 계획 총 ${d.schedules_total_minutes||0}분`,
  `- 카테고리 분포: ${categoryStr}`,
  '',
  '[이행 강도 — Execution]',
  `- 집중 세션 ${d.focus_sessions||0}회, 평균 집중도 ${pct(d.avg_focus_ratio)}%`,
  `- 계획 ${d.planned_minutes||0}분 중 실제 ${d.actual_focus_minutes||0}분 (${execRate}%)`,
  `- 등급 분포: ${gradeStr}`,
  '',
  '[체크 강도 — Completion]',
  `- 할일 ${d.todos_completed||0}/${d.todos_total||0} (${todoRate}%), 당일 체크 ${d.todos_completed_on_due_day||0}회 (${onTimeRate}%)`,
  `- 일반 일정 추가 체크 ${d.non_todo_completed||0}회`,
  '',
  `[연속 ${d.streak_days||0}일]`,
  '',
  '위 3축을 종합해 JSON 한 객체로만 응답하세요.'
].join('\n');

return [{ json: { valid: true, body, systemPrompt, userPrompt } }];

const res = $input.first().json;
let content = '';
if (typeof res.text === 'string') content = res.text;
else if (res.output && typeof res.output === 'object') content = JSON.stringify(res.output);
else if (typeof res.response === 'string') content = res.response;
else content = JSON.stringify(res);
content = content.trim();
if (content.startsWith('```')) {
  content = content.replace(/^```(?:json)?\s*\n?/i, '').replace(/\n?```\s*$/, '').trim();
}
let parsed;
try { parsed = JSON.parse(content); } catch (e) { parsed = null; }
if (!parsed || typeof parsed.summary !== 'string') {
  return [{ json: { summary: 'LLM parse failed', insights: [], suggestions: [], encouragement: '', source: 'preset' } }];
}
return [{ json: {
  summary: parsed.summary,
  insights: Array.isArray(parsed.insights) ? parsed.insights.map(String).slice(0, 5) : [],
  suggestions: Array.isArray(parsed.suggestions) ? parsed.suggestions.map(String).slice(0, 3) : [],
  encouragement: typeof parsed.encouragement === 'string' ? parsed.encouragement : '',
  source: 'llm'
}}];

const body = $input.first().json.body || {};
const d = body.data || {};
const ratio = Math.round((d.avg_focus_ratio || 0) * 100);
const todoRate = d.todos_total ? Math.round(((d.todos_completed || 0) / d.todos_total) * 100) : 0;
return [{ json: { summary: `작성 ${d.schedules_created||0}개 · 집중 ${d.focus_sessions||0}회(평균 ${ratio}%) · 체크 ${todoRate}% (연속 ${d.streak_days||0}일)`, insights: [], suggestions: [], encouragement: '수치를 확인해 보세요.', source: 'preset' } }];
